Here's an implementation of this approach in Python:

```python
def lcs(s1, s2):
    # Find length of the longest common subsequence of s1 and s2
    n1, n2 = len(s1), len(s2)
    m = [[0] * (n2 + 1) for i in range(n1 + 1)]

    for i in range(n1 + 1):
        for j in range(n2 + 1):
            if i == 0 or j == 0:
                m[i][j] = 0
            elif s1[i - 1] == s2[j - 1]:
                m[i][j] = m[i - 1][j - 1] + 1
            else:
                m[i][j] = max(m[i - 1][j], m[i][j - 1])

    # Extract LCS from matrix
    i, j = n1, n2
    lcs = ""
    while i > 0 and j > 0:
        if s1[i - 1] == s2[j - 1]:
            lcs = s1[i - 1] + lcs
            i -= 1
            j -= 1
        elif m[i - 1][j] > m[i][j - 1]:
            i -= 1
        else:
            j -= 1

    return lcs
```

